            shareLimit = jetpackSocial.shareLimit,
            publicizedCount = jetpackSocial.publicizedCount,
            sharedPostsCount = jetpackSocial.sharedPostsCount,
            sharesRemaining = jetpackSocial.sharesRemaining,
        )
